import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html'
})
export class LoginComponent {
  email = '';
  password = '';
  error = '';
  loading = false;

  constructor(private authService: AuthService, private router: Router) {}

  login(): void {
    this.error = '';
    this.loading = true;
    this.authService.login(this.email, this.password).subscribe({
      next: () => this.router.navigate(['/reserves']),
      error: () => {
        this.error = 'Email o contrasenya incorrectes.';
        this.loading = false;
      }
    });
  }
}
<div class="row justify-content-center mt-5">
  <div class="col-md-4">
    <div class="card p-4">
      <h3 class="text-center mb-4">
        <i class="bi bi-trophy-fill text-warning me-2"></i>Club Esgrima
      </h3>
      <h5 class="text-center text-muted mb-4">Iniciar sessió</h5>

      <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

      <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" [(ngModel)]="email" placeholder="correu@exemple.com">
      </div>
      <div class="mb-3">
        <label class="form-label">Contrasenya</label>
        <input type="password" class="form-control" [(ngModel)]="password" placeholder="••••••">
      </div>

      <button class="btn btn-dark w-100" (click)="login()" [disabled]="loading">
        <span *ngIf="loading" class="spinner-border spinner-border-sm me-2"></span>
        Entrar
      </button>

      <p class="text-center mt-3 mb-0">
        No tens compte? <a routerLink="/register">Registra't</a>
      </p>
    </div>
  </div>
</div>
